mapper.select:
select * from cotdl.tbl_piiconftable 
 where db= #{db}
   and owner= #{owner}
   and table_name= #{table_name}

mapper.delete:
delete from cotdl.tbl_piiconftable 
 where db= #{db}
   and owner= #{owner}
   and table_name= #{table_name}

mapper.select:
 
		 
		select 
			db, owner, table_name, pagitype, pagitypedetail, archiveflag, status, preceding, succedding, seq1, seq2, seq3, pipeline, pk_columns, pk_data_type, imatable_name, masterkey, where_col, where_key_name, parallelcnt, totalcnt, wherestr, regdate, upddate, reguserid, upduserid
		from ( 
				select
					 ROWNUM rn, db, owner, table_name, pagitype, pagitypedetail, archiveflag, status, preceding, succedding, seq1, seq2, seq3, pipeline, pk_columns, pk_data_type, imatable_name, masterkey, where_col, where_key_name, parallelcnt, totalcnt, wherestr, regdate, upddate, reguserid, upduserid
				from (
						select db, owner, table_name, pagitype, pagitypedetail, archiveflag, status, preceding, succedding, seq1, seq2, seq3, pipeline, pk_columns, pk_data_type, imatable_name, masterkey, where_col, where_key_name, parallelcnt, totalcnt, wherestr, to_char(regdate,'yyyy/mm/dd') as regdate, to_char(upddate,'yyyy/mm/dd') as upddate, reguserid, upduserid
						  from cotdl.tbl_piiconftable order by db desc, seq1, seq2, seq3
					 ) f
				where 
		
	    
		
						
							and db like '%'||#{search1}||'%'
						
						
							and owner like '%'||#{search2}||'%'
						
						
							and table_name like '%'||#{search3}||'%'
						
		
	    
	    
				 ROWNUM <= #{pagenum} * #{amount} 
				order by db desc, seq1, seq2, seq3
			  ) r
		where rn > (#{pagenum} -1) * #{amount}
		order by db desc, seq1, seq2, seq3
